package main
import "testing"
func TestPower(t *testing.T) {
 cases := []struct{b, e, want int}{{2,3,8}, {5,0,1}, {10,2,100}, {0,5,0}}
 for _, c := range cases {
 if got := Power(c.b, c.e); got != c.want {
 t.Errorf("Power(%d, %d) = %d; want %d", c.b, c.e, got, c.want)
 }
 }
}

package main
