func TestIsLeapYear(t *testing.T) {
 cases := []struct{y int; want bool}{{2000,true}, {1900,false}, {2024,true}, {2023,false}, {2001,false}}
 for _, c := range cases {
 if got := IsLeapYear(c.y); got != c.want {
 t.Errorf("IsLeapYear(%d) = %v; want %v", c.y, got, c.want)
 }
 }
}

